def longest_subsequence_sum(nums, target):
    # dp[i] will store the maximum length of a subsequence that sums to i
    dp = [-1] * (target + 1)
    dp[0] = 0  # sum 0 can always be achieved with empty subsequence

    for num in nums:
        # iterate backwards to avoid reusing the same element
        for s in range(target, num - 1, -1):
            if dp[s - num] != -1:
                dp[s] = max(dp[s], dp[s - num] + 1)

    return dp[target] if dp[target] != -1 else -1
